import React, { useState, useEffect, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import api from '../utils/api';
import { useAuth } from '../context/AuthContext';
import { StatusBadge, PriorityBadge, formatDate, isOverdue } from '../utils/statusHelpers';
import Sidebar from '../components/common/Sidebar';

export default function RequestsPage() {
  const { user } = useAuth();
  const navigate = useNavigate();
  const [requests, setRequests] = useState([]);
  const [total, setTotal] = useState(0);
  const [page, setPage] = useState(1);
  const [loading, setLoading] = useState(true);
  const [filters, setFilters] = useState({
    status: '', priority: '', search: '', overdue: '', blocked: '', department: '',
  });

  const fetchRequests = useCallback(async () => {
    setLoading(true);
    try {
      const params = new URLSearchParams({ page, limit: 25, ...filters });
      Object.keys(filters).forEach(k => !filters[k] && params.delete(k));
      const res = await api.get(`/requests?${params}`);
      setRequests(res.data.requests);
      setTotal(res.data.total);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  }, [page, filters]);

  useEffect(() => { fetchRequests(); }, [fetchRequests]);

  const handleFilterChange = (key, value) => {
    setFilters(f => ({ ...f, [key]: value }));
    setPage(1);
  };

  const canCreateRequest = ['requester', 'coordinator', 'administrator'].includes(user?.role);

  return (
    <div className="page">
      <Sidebar />
      <div className="main-content">
        <div className="page-header">
          <div>
            <h1 style={{ fontSize: '1.3rem', fontFamily: 'var(--font-heading)' }}>
              {user?.role === 'requester' ? 'My Requests' : 'All Requests'}
            </h1>
            <p style={{ color: 'var(--text-muted)', fontSize: '0.8rem', marginTop: '0.2rem' }}>
              {total} request{total !== 1 ? 's' : ''} found
            </p>
          </div>
          {canCreateRequest && (
            <button className="btn btn-primary" onClick={() => navigate('/requests/new')}>
              <svg width="14" height="14" fill="none" stroke="currentColor" strokeWidth="2.5" viewBox="0 0 24 24">
                <line x1="12" y1="5" x2="12" y2="19"/><line x1="5" y1="12" x2="19" y2="12"/>
              </svg>
              New Request
            </button>
          )}
        </div>

        {/* Filters */}
        <div style={{ padding: '1rem 2rem', borderBottom: '1px solid var(--border)', display: 'flex', gap: '0.75rem', flexWrap: 'wrap' }}>
          <input
            className="form-input" placeholder="Search by title, ID, description…"
            value={filters.search} onChange={e => handleFilterChange('search', e.target.value)}
            style={{ width: 240 }}
          />
          <select className="form-select" value={filters.status} onChange={e => handleFilterChange('status', e.target.value)} style={{ width: 180 }}>
            <option value="">All Statuses</option>
            {['draft','submitted','completeness_check','feasibility_review','more_info_required',
              'approved','rejected','prioritized','planned','assigned','in_progress','printed',
              'post_processing','quality_check','ready_for_pickup','completed','archived',
              'on_hold','blocked','cancelled','rework_required'].map(s => (
              <option key={s} value={s}>{s.replace(/_/g,' ')}</option>
            ))}
          </select>
          <select className="form-select" value={filters.priority} onChange={e => handleFilterChange('priority', e.target.value)} style={{ width: 140 }}>
            <option value="">All Priorities</option>
            <option value="critical">Critical</option>
            <option value="high">High</option>
            <option value="normal">Normal</option>
            <option value="low">Low</option>
          </select>
          {user?.role !== 'requester' && (
            <>
              <button
                className={`btn ${filters.overdue === 'true' ? 'btn-danger' : 'btn-ghost'} btn-sm`}
                onClick={() => handleFilterChange('overdue', filters.overdue === 'true' ? '' : 'true')}
              >Overdue</button>
              <button
                className={`btn ${filters.blocked === 'true' ? 'btn-danger' : 'btn-ghost'} btn-sm`}
                onClick={() => handleFilterChange('blocked', filters.blocked === 'true' ? '' : 'true')}
              >Blocked</button>
            </>
          )}
          {(filters.status || filters.priority || filters.search || filters.overdue || filters.blocked) && (
            <button className="btn btn-ghost btn-sm" onClick={() => { setFilters({ status:'',priority:'',search:'',overdue:'',blocked:'',department:'' }); setPage(1); }}>
              Clear filters
            </button>
          )}
        </div>

        <div className="page-body">
          {loading ? (
            <div style={{ display: 'flex', justifyContent: 'center', padding: '3rem' }}>
              <span className="spinner" style={{ width: 28, height: 28 }}/>
            </div>
          ) : requests.length === 0 ? (
            <div className="empty-state">
              <svg width="48" height="48" fill="none" stroke="currentColor" strokeWidth="1.5" viewBox="0 0 24 24">
                <path d="M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2"/>
                <rect x="9" y="3" width="6" height="4" rx="1"/>
              </svg>
              <p style={{ marginTop: '0.5rem' }}>No requests found</p>
              {canCreateRequest && (
                <button className="btn btn-primary" style={{ marginTop: '1rem' }} onClick={() => navigate('/requests/new')}>
                  Create first request
                </button>
              )}
            </div>
          ) : (
            <>
              <div className="table-container card" style={{ padding: 0 }}>
                <table>
                  <thead>
                    <tr>
                      <th>ID</th>
                      <th>Title</th>
                      <th>Status</th>
                      <th>Priority</th>
                      {user?.role !== 'requester' && <th>Requester</th>}
                      {user?.role !== 'requester' && <th>Department</th>}
                      <th>Due Date</th>
                      {['coordinator','administrator','manager'].includes(user?.role) && <th>Technician</th>}
                      <th>Created</th>
                    </tr>
                  </thead>
                  <tbody>
                    {requests.map(r => (
                      <tr
                        key={r.id}
                        className={isOverdue(r) ? 'row-overdue' : ''}
                        style={{ cursor: 'pointer' }}
                        onClick={() => navigate(`/requests/${r.id}`)}
                      >
                        <td style={{ fontFamily: 'var(--font-mono)', fontSize: '0.78rem', color: 'var(--accent)', fontWeight: 600 }}>
                          {r.request_number}
                        </td>
                        <td style={{ maxWidth: 280 }}>
                          <div style={{ fontWeight: 500, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
                            {r.title}
                          </div>
                          {r.category_name && (
                            <div style={{ fontSize: '0.72rem', color: 'var(--text-muted)', marginTop: '0.1rem' }}>
                              {r.category_name}
                            </div>
                          )}
                        </td>
                        <td><StatusBadge status={r.status}/></td>
                        <td><PriorityBadge priority={r.priority}/></td>
                        {user?.role !== 'requester' && <td style={{ fontSize: '0.82rem' }}>{r.requester_name || '—'}</td>}
                        {user?.role !== 'requester' && <td style={{ fontSize: '0.8rem', color: 'var(--text-secondary)' }}>{r.requester_department || '—'}</td>}
                        <td style={{ fontSize: '0.8rem', color: isOverdue(r) ? 'var(--red)' : 'var(--text-secondary)' }}>
                          {r.approved_due_date ? (
                            <>{formatDate(r.approved_due_date)}{isOverdue(r) && <span style={{ marginLeft: '0.3rem', fontSize: '0.68rem', color: 'var(--red)', fontWeight: 700 }}>OVERDUE</span>}</>
                          ) : '—'}
                        </td>
                        {['coordinator','administrator','manager'].includes(user?.role) && (
                          <td style={{ fontSize: '0.82rem', color: 'var(--text-secondary)' }}>{r.technician_full_name || '—'}</td>
                        )}
                        <td style={{ fontSize: '0.8rem', color: 'var(--text-muted)' }}>{formatDate(r.created_at)}</td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>

              {/* Pagination */}
              {total > 25 && (
                <div style={{ display: 'flex', justifyContent: 'center', gap: '0.5rem', marginTop: '1.5rem' }}>
                  <button className="btn btn-ghost btn-sm" disabled={page === 1} onClick={() => setPage(p => p - 1)}>← Prev</button>
                  <span style={{ padding: '0.35rem 0.75rem', fontSize: '0.8rem', color: 'var(--text-secondary)' }}>
                    Page {page} of {Math.ceil(total / 25)}
                  </span>
                  <button className="btn btn-ghost btn-sm" disabled={page >= Math.ceil(total / 25)} onClick={() => setPage(p => p + 1)}>Next →</button>
                </div>
              )}
            </>
          )}
        </div>
      </div>
    </div>
  );
}
